{
  "project": "mms-demo",
  "version": "0.1.0",
  "description": "Fractal Canvas - Train Maintenance Planner Demo",
  "stack": {
    "framework": "Astro",
    "ui": ["React 19", "MUI v6"],
    "state": "Redux Toolkit",
    "language": "TypeScript",
    "testing": ["Vitest", "Playwright", "Storybook"],
    "quality": ["ESLint", "Prettier", "Husky", "lint-staged"],
    "backend": "none (prepared for future)"
  },
  "setup": [
    { "id": "setup-001", "name": "Initialize Astro project with TypeScript", "status": "pending" },
    { "id": "setup-002", "name": "Install React 19 integration", "status": "pending" },
    { "id": "setup-003", "name": "Install MUI v6", "status": "pending" },
    { "id": "setup-004", "name": "Install Redux Toolkit", "status": "pending" },
    { "id": "setup-005", "name": "Configure ESLint + Prettier", "status": "pending" },
    { "id": "setup-006", "name": "Setup Husky + lint-staged (pre-commit hooks)", "status": "pending" },
    { "id": "setup-007", "name": "Setup Playwright for E2E and visual regression", "status": "pending" },
    { "id": "setup-008", "name": "Setup Storybook for component documentation", "status": "pending" }
  ],
  "features": {
    "core-canvas": [
      { "id": "canvas-001", "name": "FractalCanvas main component", "status": "pending" },
      { "id": "canvas-002", "name": "Pan/drag functionality", "status": "pending" },
      { "id": "canvas-003", "name": "Zoom functionality (10%-100%)", "status": "pending" },
      { "id": "canvas-004", "name": "Semantic zoom level detection", "status": "pending" }
    ],
    "strategic-view": [
      { "id": "strat-001", "name": "Capacity heatmap (12 years)", "status": "pending" },
      { "id": "strat-002", "name": "Fleet rows rendering", "status": "pending" },
      { "id": "strat-003", "name": "Drag overhaul blocks", "status": "pending" }
    ],
    "tactical-view": [
      { "id": "tact-001", "name": "Workload equalizer", "status": "pending" },
      { "id": "tact-002", "name": "Monthly breakdown", "status": "pending" },
      { "id": "tact-003", "name": "Auto-Level redistribution", "status": "pending" }
    ],
    "operational-view": [
      { "id": "oper-001", "name": "Train capsules", "status": "pending" },
      { "id": "oper-002", "name": "Track lanes", "status": "pending" },
      { "id": "oper-003", "name": "Drag trains between routes", "status": "pending" }
    ],
    "constraint-deck": [
      { "id": "deck-001", "name": "Sidebar component", "status": "pending" },
      { "id": "deck-002", "name": "Context-aware controls", "status": "pending" },
      { "id": "deck-003", "name": "What-If simulation", "status": "pending" }
    ],
    "state-management": [
      { "id": "redux-001", "name": "Redux store setup", "status": "pending" },
      { "id": "redux-002", "name": "Canvas slice (zoom, pan)", "status": "pending" },
      { "id": "redux-003", "name": "Fleet slice (trains data)", "status": "pending" },
      { "id": "redux-004", "name": "Schedule slice (maintenance)", "status": "pending" },
      { "id": "redux-005", "name": "Simulation slice (what-if)", "status": "pending" }
    ],
    "data-layer": [
      { "id": "data-001", "name": "Mock data for 128 trains", "status": "pending" },
      { "id": "data-002", "name": "Simulated API delay (fast)", "status": "pending" },
      { "id": "data-003", "name": "API service layer (ready for backend)", "status": "pending" }
    ]
  }
}

